<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';use VP3\Mail\MailerFactory;$complete=false;
if(vp3_method()==='POST'){vp3_verify_csrf();$email=strtolower(vp3_input('email'));if(filter_var($email,FILTER_VALIDATE_EMAIL)&&vp3_db_available()&&vp3_rate_limit('viewer-password-reset:'.$email,3,3600)){$stmt=vp3_db()->prepare("SELECT id FROM viewer_accounts WHERE email=? AND status='active' LIMIT 1");$stmt->execute([$email]);$id=(int)($stmt->fetchColumn()?:0);if($id>0){$token=vp3_secure_token();vp3_db()->prepare('INSERT INTO viewer_password_resets (viewer_id,token_hash,expires_at,created_at) VALUES (?,?,DATE_ADD(NOW(),INTERVAL 30 MINUTE),NOW())')->execute([$id,vp3_hash_token($token)]);$url=vp3_url('viewer-reset-password.php?token='.rawurlencode($token));MailerFactory::make()->send($email,'Reset your VP3 viewer password',"Reset your viewer password: {$url}\n\nThis link expires in 30 minutes.");vp3_audit('viewer',$id,'viewer.password_reset_requested','viewer',(string)$id);}}$complete=true;}
$pageTitle='Viewer Password Recovery';$bodyClass='auth-page viewer-auth-page';$extraStyles=['assets/css/reels.css'];require VP3_ROOT.'/includes/header.php';?>
<section class="auth-layout compact-auth"><div class="auth-panel"><div class="auth-panel-inner"><span class="eyebrow">Viewer recovery</span><h1>Reset your password.</h1><?php if($complete):?><p>If an eligible viewer account exists, reset instructions have been queued.</p><a class="button auth-submit" href="viewer-login.php">Return to viewer sign in</a><?php else:?><p class="auth-intro">Enter the email used for your viewer profile. The response will not reveal whether an account exists.</p><form method="post"><?=vp3_csrf_field()?><div class="field"><label>Email<input type="email" name="email" required></label></div><button class="button auth-submit">Send reset instructions</button></form><?php endif;?></div></div></section>
<?php require VP3_ROOT.'/includes/footer.php';?>
